// Convierte MAX(last_sync) de Postgres a Unix timestamp.
// Incluye pg_count para detectar contactos nuevos en Mailjet.
// Fuerza sync completa (ts=0):
//   - Los domingos (garantía de consistencia semanal)
//   - Si force_full=true en el Manual Trigger (forzado manual)
const raw     = $input.first().json.last_sync;
const pgCount = Number($input.first().json.pg_count ?? 0);

const esDomingoSync = new Date().getDay() === 0;

// Ejecución manual → sync completa por defecto.
// Motivo: los cambios manuales de propiedades en Mailjet NO actualizan LastActivityAt,
// así que la delta nunca los detectaría. Si quieres forzar delta en manual,
// pasa force_full=false explícitamente en el trigger.
let forceFull = false;
try {
  const manualNode = $('When clicking \'Execute workflow\'');
  if (manualNode.isExecuted) {
    // Por defecto true en manual; false solo si se pasa explícitamente
    forceFull = Boolean(manualNode.first()?.json?.force_full ?? true);
  }
} catch(e) {
  forceFull = false;
}

const ts = (raw && !esDomingoSync && !forceFull)
  ? Math.floor(new Date(raw).getTime() / 1000)
  : 0;

return [{
  json: {
    last_sync_unix: ts,
    pg_count:       pgCount,
    force_full:     forceFull,
    ts_inicio:      Date.now(),
    fecha_inicio:   new Date().toISOString()
  }
}];

// Compara conteo delta (LastActivityAt) vs total Mailjet vs total Postgres.
// Si hay contactos nuevos en Mailjet → fuerza sync completa (ts_efectivo = 0).
// Si solo hay actividad email → sync parcial con ts original.
// Expone total_a_procesar para que Code Generar Páginas calcule las páginas correctas.
const items = $input.all();
const ctx   = $('Code Preparar Contexto').first().json;

const totales      = items.map(i => Number(i.json.Total ?? 0));
const deltaTotal   = Math.min(...totales); // filtrado por LastActivityAt → ≤ total
const mailjetTotal = Math.max(...totales); // sin filtro → el mayor

const hayNuevos      = mailjetTotal > ctx.pg_count;
const tsEfectivo     = hayNuevos ? 0 : ctx.last_sync_unix;
const totalAProcesar = hayNuevos ? mailjetTotal : deltaTotal;
const hayCambios     = totalAProcesar > 0;

return [{
  json: {
    ts_efectivo:      tsEfectivo,
    hay_cambios:      hayCambios,
    total_a_procesar: totalAProcesar,
    hay_nuevos:       hayNuevos,
    delta_total:      deltaTotal,
    mailjet_total:    mailjetTotal,
    pg_count:         ctx.pg_count,
    ts_inicio:        ctx.ts_inicio,
    fecha_inicio:     ctx.fecha_inicio
  }
}];

// Genera un item por página a paginar.
// Usa total_a_procesar: puede ser delta o total Mailjet si hay nuevos contactos.
// Propaga ts_efectivo como last_sync_unix para el filtro de HTTP GET Contacts Page.
const total = Number($json.total_a_procesar ?? 0);
const limit = 1000;
const pages = Math.max(1, Math.ceil(total / limit));
const ts_efectivo = $('Code Decidir ts_efectivo').first().json.ts_efectivo;
return Array.from({ length: pages }, (_, i) => ({
  json: { offset: i * limit, pageLimit: limit, last_sync_unix: ts_efectivo }
}));

const now      = new Date().toISOString();
const contacts = $('Set Guardar Contexto').item.json._contacts || [];
const dataRows = $input.item.json.Data || [];

const fields = ["nombre","poblacion","provincia","zona_geografica","zona_comercial",
  "estado","razon_social","centro_reparto","comercial_recambio","comercial_equipamiento",
  "comercial_pincar","comercial_redes","coordinador_recambio","canal","tipo_cliente","red",
  "sub_red","subcanal","division","envio_promociones","tipo_cliente_dto","activo","distribuidor","cif",
  "distribuidor_vemare","distribuidor_transcose","distribuidor_dieseliberia","distribuidor_paher",
  "codigo_isi_vemare","codigo_isi_transcose","codigo_isi_dieseliberia","codigo_isi_paher"];

const clasificarTelefono = (raw) => {
  if (!raw) return { normalizado: '', tipo: 'vacio' };
  let digits = String(raw).replace(/\D/g, '');
  if (digits.startsWith('0034') && digits.length === 13) digits = digits.slice(4);
  else if (digits.startsWith('34') && digits.length === 11) digits = digits.slice(2);
  if (digits.length !== 9) return { normalizado: '', tipo: 'invalido' };
  const inicio = digits[0];
  if (inicio === '6' || inicio === '7') return { normalizado: '+34' + digits, tipo: 'movil' };
  if (inicio === '9' || inicio === '8') return { normalizado: '+34' + digits, tipo: 'fijo' };
  return { normalizado: '', tipo: 'invalido' };
};

const propMap = {};
for (const row of dataRows) {
  const props = {};
  for (const p of (row.Data || [])) props[p.Name] = p.Value;
  propMap[String(row.ContactID)] = props;
}

return contacts.map(c => {
  const props = propMap[String(c.ID)] || {};
  const row = { id: c.ID, email: c.Email, last_sync: now };
  for (const f of fields) row[f] = props[f] ?? '';
  const t1 = clasificarTelefono(props.telefono_1);
  const t2 = clasificarTelefono(props.telefono_2);
  row.telefono_1      = t1.normalizado;
  row.telefono_1_tipo = t1.tipo;
  row.telefono_2      = t2.normalizado;
  row.telefono_2_tipo = t2.tipo;
  row.telefono_wa     = t1.tipo === 'movil' ? t1.normalizado
                      : t2.tipo === 'movil' ? t2.normalizado
                      : '';
  row.listas_mailjet  = '';
  return { json: row };
});

// Colapsa los N contactos delta a 1 item para que Wait y Fase 2
// se ejecuten una sola vez independientemente del número de páginas.
return [{ json: { ok: true } }];

const total = Number($json.Total ?? 0);
const limit = 1000;
const pages = Math.max(1, Math.ceil(total / limit));
return Array.from({ length: pages }, (_, i) => ({
  json: { offset: i * limit, pageLimit: limit }
}));

// Solo procesa los contactos que forman parte del delta (Fase 1).
// Fase 2 siempre descarga todas las listas de Mailjet, pero solo
// emite filas para los contactos que cambiaron en esta ejecución.

const deltaItems = $('Code Unir y Normalizar').all();
const deltaIds   = new Set(deltaItems.map(i => String(i.json.id)));

// Lookup de datos completos por id
const contactMap = {};
for (const item of deltaItems) {
  contactMap[String(item.json.id)] = item.json;
}

// Acumular listas solo para ids delta
const listasMapa = {};
for (const item of $input.all()) {
  for (const row of (item.json.Data || [])) {
    const cid = String(row.ContactID);
    if (!deltaIds.has(cid)) continue;
    const lista = row.ContactsListName || String(row.ListID);
    if (!listasMapa[cid]) listasMapa[cid] = new Set();
    listasMapa[cid].add(lista);
  }
}

// Emitir fila completa por cada contacto delta
return [...deltaIds].map(cid => {
  const c = contactMap[cid] || {};
  return {
    json: {
      id_mailjet:             Number(cid),
      listas_mailjet:         listasMapa[cid] ? [...listasMapa[cid]].join(',') : '',
      email:                  c.email ?? '',
      last_sync:              c.last_sync ?? '',
      nombre:                 c.nombre ?? '',
      poblacion:              c.poblacion ?? '',
      razon_social:           c.razon_social ?? '',
      provincia:              c.provincia ?? '',
      zona_geografica:        c.zona_geografica ?? '',
      zona_comercial:         c.zona_comercial ?? '',
      estado:                 c.estado ?? '',
      centro_reparto:         c.centro_reparto ?? '',
      comercial_recambio:     c.comercial_recambio ?? '',
      comercial_equipamiento: c.comercial_equipamiento ?? '',
      comercial_pincar:       c.comercial_pincar ?? '',
      comercial_redes:        c.comercial_redes ?? '',
      coordinador_recambio:   c.coordinador_recambio ?? '',
      canal:                  c.canal ?? '',
      tipo_cliente:           c.tipo_cliente ?? '',
      red:                    c.red ?? '',
      sub_red:                c.sub_red ?? '',
      subcanal:               c.subcanal ?? '',
      division:               c.division ?? '',
      envio_promociones:      c.envio_promociones ?? '',
      tipo_cliente_dto:       c.tipo_cliente_dto ?? '',
      activo:                 c.activo ?? '',
      distribuidor:           c.distribuidor ?? '',
      cif:                    c.cif ?? '',
      telefono_1:             c.telefono_1 ?? '',
      telefono_1_tipo:        c.telefono_1_tipo ?? '',
      telefono_2:             c.telefono_2 ?? '',
      telefono_2_tipo:        c.telefono_2_tipo ?? '',
      telefono_wa:            c.telefono_wa ?? '',
      distribuidor_vemare:     c.distribuidor_vemare ?? '',
      distribuidor_transcose:  c.distribuidor_transcose ?? '',
      distribuidor_dieseliberia: c.distribuidor_dieseliberia ?? '',
      distribuidor_paher:      c.distribuidor_paher ?? '',
      codigo_isi_vemare:       c.codigo_isi_vemare ?? '',
      codigo_isi_transcose:    c.codigo_isi_transcose ?? '',
      codigo_isi_dieseliberia: c.codigo_isi_dieseliberia ?? '',
      codigo_isi_paher:        c.codigo_isi_paher ?? ''
    }
  };
});

// Calcula métricas de la ejecución y prepara el registro de log.
// ts_inicio y fecha_inicio se leen desde Code Preparar Contexto.
// NOTA: Habilitar este nodo cuando la tabla sync_log esté creada.
const tsInicio    = $('Code Preparar Contexto').first().json.ts_inicio;
const fechaInicio = $('Code Preparar Contexto').first().json.fecha_inicio;
const contactosProcesados = $('Code Consolidar Listas').all().length;
const fechaFin   = new Date().toISOString();
const duracionMs = Date.now() - tsInicio;

return [{
  json: {
    fecha_inicio:         fechaInicio,
    fecha_fin:            fechaFin,
    duracion_ms:          duracionMs,
    contactos_procesados: contactosProcesados,
    estado:               'ok'
  }
}];

// Extrae los IDs Mailjet del delta de Fase 1.
// Genera 1 item por contacto con su idmailjet para el HTTP batch.
const deltaItems = $('Code Unir y Normalizar').all();
return deltaItems.map(item => ({
  json: { idmailjet: item.json.id }
}));

// Recibe N responses de getcontactslists (1 por contacto del delta).
// Construye el mismo formato que Code Consolidar Listas1 para reutilizar el Upsert.
const deltaItems = $('Code Unir y Normalizar').all();
const deltaIds   = $('Code IDs Delta para Listas').all();
const contactMap = {};
for (const item of deltaItems) {
  contactMap[String(item.json.id)] = item.json;
}

// input.all() tiene 1 item por contacto con json.Data = [{ListID, Name, ...}]
return $input.all().map((item, idx) => {
  const id_mailjet = deltaIds[idx]?.json.idmailjet;
  const c = contactMap[String(id_mailjet)] ?? {};
  const listas_mailjet = (item.json.Data ?? [])
    .map(l => (l.Name || String(l.ListID)))
    .join(',');

  return {
    json: {
      id_mailjet,
      listas_mailjet,
      email:                    c.email ?? '',
      last_sync:                c.last_sync ?? '',
      nombre:                   c.nombre ?? '',
      poblacion:                c.poblacion ?? '',
      razon_social:             c.razon_social ?? '',
      provincia:                c.provincia ?? '',
      zona_geografica:          c.zona_geografica ?? '',
      zona_comercial:           c.zona_comercial ?? '',
      estado:                   c.estado ?? '',
      centro_reparto:           c.centro_reparto ?? '',
      comercial_recambio:       c.comercial_recambio ?? '',
      comercial_equipamiento:   c.comercial_equipamiento ?? '',
      comercial_pincar:         c.comercial_pincar ?? '',
      comercial_redes:          c.comercial_redes ?? '',
      coordinador_recambio:     c.coordinador_recambio ?? '',
      canal:                    c.canal ?? '',
      tipo_cliente:             c.tipo_cliente ?? '',
      red:                      c.red ?? '',
      sub_red:                  c.sub_red ?? '',
      subcanal:                 c.subcanal ?? '',
      division:                 c.division ?? '',
      envio_promociones:        c.envio_promociones ?? '',
      tipo_cliente_dto:         c.tipo_cliente_dto ?? '',
      activo:                   c.activo ?? '',
      distribuidor:             c.distribuidor ?? '',
      cif:                      c.cif ?? '',
      telefono_1:               c.telefono_1 ?? '',
      telefono_1_tipo:          c.telefono_1_tipo ?? '',
      telefono_2:               c.telefono_2 ?? '',
      telefono_2_tipo:          c.telefono_2_tipo ?? '',
      telefono_wa:              c.telefono_wa ?? '',
      distribuidor_vemare:      c.distribuidor_vemare ?? '',
      distribuidor_transcose:   c.distribuidor_transcose ?? '',
      distribuidor_dieseliberia: c.distribuidor_dieseliberia ?? '',
      distribuidor_paher:       c.distribuidor_paher ?? '',
      codigo_isi_vemare:        c.codigo_isi_vemare ?? '',
      codigo_isi_transcose:     c.codigo_isi_transcose ?? '',
      codigo_isi_dieseliberia:  c.codigo_isi_dieseliberia ?? '',
      codigo_isi_paher:         c.codigo_isi_paher ?? ''
    }
  };
});
